/** Resolve a Material3 [ColorScheme] for a [org.nekosukuriputo.nekuva.core.prefs.ColorScheme] enum name. */
fun appColorScheme(schemeName: String, dark: Boolean): ColorScheme = when (schemeName) {
    "MIKU" -> if (dark) MikuDark else MikuLight
    "RENA" -> if (dark) AsukaDark else AsukaLight
    "FROG" -> if (dark) MionDark else MionLight
    "BLUEBERRY" -> if (dark) RikkaDark else RikkaLight
    "SAKURA" -> if (dark) SakuraDark else SakuraLight
    "MAMIMI" -> if (dark) MamimiDark else MamimiLight
    "KANADE" -> if (dark) KanadeDark else KanadeLight
    "ITSUKA" -> if (dark) ItsukaDark else ItsukaLight
    else -> if (dark) TotoroDark else TotoroLight // DEFAULT/MONET/EXPRESSIVE fallback
}

/** Pure-black AMOLED variant of a dark [ColorScheme] (keeps the theme accent). */
fun ColorScheme.toAmoled(): ColorScheme = copy(
    background = Color.Black,
    surface = Color.Black,
    surfaceDim = Color.Black,
    surfaceContainerLowest = Color.Black,
    surfaceContainerLow = Color(0xFF0A0A0A),
    surfaceContainer = Color(0xFF101010),
    surfaceContainerHigh = Color(0xFF161616),
    surfaceContainerHighest = Color(0xFF1C1C1C),
)
